  7005→     * Prepare a rebalance.
  7006→     *
  7007→     * @param group           The group to rebalance.
  7008→     * @param reason          The reason for the rebalance.
  7009→     *
  7010→     * @return The coordinator result that will be appended to the log.
  7011→     *
  7012→     * Package private for testing.
  7013→     */
  7014→    CoordinatorResult<Void, CoordinatorRecord> prepareRebalance(
  7015→        ClassicGroup group,
  7016→        String reason
  7017→    ) {
  7018→        // If any members are awaiting sync, cancel their request and have them rejoin.
  7019→        if (group.isInState(COMPLETING_REBALANCE)) {
  7020→            resetAndPropagateAssignmentWithError(group, Errors.REBALANCE_IN_PROGRESS);
  7021→        }
  7022→
  7023→        // If a sync expiration is pending, cancel it.
  7024→        removeSyncExpiration(group);
  7025→
  7026→        boolean isInitialRebalance = group.isInState(EMPTY);
  7027→        if (isInitialRebalance) {
  7028→            // The group is new. Provide more time for the members to join.
  7029→            int delayMs = config.classicGroupInitialRebalanceDelayMs();
  7030→            int remainingMs = Math.max(group.rebalanceTimeoutMs() - config.classicGroupInitialRebalanceDelayMs(), 0);
  7031→
  7032→            timer.schedule(
  7033→                classicGroupJoinKey(group.groupId()),
  7034→                delayMs,
  7035→                TimeUnit.MILLISECONDS,
  7036→                false,
  7037→                () -> tryCompleteInitialRebalanceElseSchedule(group.groupId(), delayMs, remainingMs)
  7038→            );
  7039→        }
  7040→
  7041→        group.transitionTo(PREPARING_REBALANCE);
  7042→
  7043→        log.info("Preparing to rebalance group {} in state {} with old generation {} (reason: {}).",
  7044→            group.groupId(), group.currentState(), group.generationId(), reason);
  7045→
  7046→        return isInitialRebalance ? EMPTY_RESULT : maybeCompleteJoinElseSchedule(group);
